class Node:
    def __init__(self, data):
        self.data = data
        self.next = None

class LinkedList:        
    def __init__(self):
        self.head = None
        self.count = 0
        
    def add(self, new):
        new_node = Node(new)
        new_node.next = None
        if self.head is None:
            self.head = new_node
        else:
            cur = self.head
            while cur.next is not None:
                cur = cur.next
            cur.next = new_node
        self.count += 1
                
    def print_list(self):
        current = self.head
        while current is not None:
            print(current.data, end=" -> ")
            current = current.next
        print("None")
        
    def size(self):
        return self.count
